import csv

def process_csv(filename):
    """
    Reads a CSV file with columns 'name', 'score', 'grade' and returns a dict 
    with keys 'average_score' (float) and 'a_students' (list of names with grade 'A').
    """
    data = []
    try:
        with open(filename, 'r') as csvfile:
            reader = csv.DictReader(csvfile)
            for row in reader:
                data.append(row)
    except FileNotFoundError:
        return {'average_score': 0.0, 'a_students': []}

    total_score = 0
    num_students = len(data)
    a_students = []

    for student in data:
        try:
            score = float(student['score'])
            grade = student['grade']
            total_score += score
            if grade == 'A':
                a_students.append(student['name'])
        except ValueError:
            continue  # Skip rows with invalid scores

    average_score = total_score / num_students if num_students > 0 else 0.0

    return {'average_score': average_score, 'a_students': a_students}

def fizzbuzz(n):
    """
    Returns a list of length n where the i-th element (1-indexed) is 'FizzBuzz' if i is divisible by 15,
    'Fizz' if divisible by 3, 'Buzz' if divisible by 5, otherwise the number i as a string.
    """
    result = []
    for i in range(1, n + 1):
        if i % 15 == 0:
            result.append('FizzBuzz')
        elif i % 3 == 0:
            result.append('Fizz')
        elif i % 5 == 0:
            result.append('Buzz')
        else:
            result.append(str(i))
    return result

