use strict;
use warnings;

if (@ARGV != 1) {
    die "Usage: $0 <filename>\n";
}

my $filename = $ARGV[0];

open(my $fh, '<', $filename) or die "Could not open file '$filename': $!";

my $total_lines = 0;
my $error_lines = 0;

while (my $line = <$fh>) {
    $total_lines++;
    if ($line =~ /error/i) {
        $error_lines++;
    }
}

close($fh);

print "$total_lines\n";
print "$error_lines\n";

using UnityEngine;

public class FirstPersonController : MonoBehaviour
{
    [Header("Movement")]
    public float moveSpeed = 5f;
    public float rotationSpeed = 200f;

    [Header("Jump")]
    public float jumpHeight = 6f;
    public float gravityMultiplier = -2f;

    private CharacterController controller;
    private Vector3 velocity;

    void Start()
    {
        controller = GetComponent<CharacterController>();
        if (controller == null)
        {
            Debug.LogError("CharacterController not found on this GameObject.");
            enabled = false;
        }
    }

    void Update()
    {
        // Movement
        float x = Input.GetAxis("Horizontal") * moveSpeed;
        float z = Input.GetAxis("Vertical") * moveSpeed;

        Vector3 moveDirection = transform.forward * z + transform.right * x;
        moveDirection.Normalize();

        controller.Move(moveDirection * Time.deltaTime);

        // Mouse Look
        float mouseX = Input.GetAxis("Mouse X") * rotationSpeed;
        transform.Rotate(Vector3.up * mouseX);

        // Jump
        if (IsGrounded())
        {
            if (Input.GetButtonDown("Jump"))
            {
                velocity.y = Mathf.Sqrt(jumpHeight * 2f * gravityMultiplier);
            }
        }

        // Gravity
        velocity.y += gravityMultiplier * Time.deltaTime;
        controller.Move(velocity * Time.deltaTime);
    }

    private bool IsGrounded()
    {
        return controller.isGrounded;
    }
}
